#!/usr/bin/env bash
# agentic.sh — Agentic Protocol CLI for 侍酒师与葡萄酒.
# Auto-generated by cli_writer.py. Source: synthesis.md Section 9.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
# shellcheck source=../lib/common.sh
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="侍酒师与葡萄酒"
DIM_COUNT=7

usage() {
  cat <<EOF
agentic.sh — Agentic Protocol CLI for ${INDUSTRY}

拿到 ${INDUSTRY} 行业的新问题时，按 ${DIM_COUNT} 个研究维度做功课再答。
不直接给答案，而是引导你用资深从业者的研究维度收集信息。

USAGE:
  ./agentic.sh                # interactive walkthrough
  ./agentic.sh --dry-run      # walk through but skip file write
  ./agentic.sh --json         # emit JSON to stdout
  ./agentic.sh --explain      # show backing mental models + sources
  ./agentic.sh --help         # this message
EOF
}

explain() {
  cat <<'EOT'
这个 Agentic Protocol 把这一行人面对新问题的研究维度结构化。

研究维度 (7 个):
  9.1 地理与世界观定位（terroir-first）
  9.2 结构化品鉴（SAT / deductive grid）
  9.3 信源与分数解码
  9.4 配餐推理
  9.5 法规 / 分级 / 合规定位
  9.6 张力轴定位
  9.7 时效与近期变化

背后的心智模型:
  • terroir-first（地理是第一性问题,旧世界尤甚）: 遇到一支酒,资深人的**第一个问题不是「什么品种 / 好不好喝」,而是「它来自哪——那块地的气 / 土 / 人为传统如何」**;terroir(风土)是不可复制、不可移植的组织原语,旧世界直接「以产地
  • codifiable 理论层 ⇄ tacit 校准层（双层不可互替）: 葡萄酒认知是**两层**——可背诵的理论(产区 / 法规 / 品种 / 酿造化学)和不可言传的校准(味觉记忆 / 盲品 / 侍酒服务);两层**不可互相替代**,读一百本书也代替不了真酒重复。
  • 盲品 = 结构化演绎：结构(骨架)先于香气(血肉): 盲品不是天赋直觉,是**把感官线索逼成可走查、可被他人核对的演绎**;且**先抓 structure(酸 / 单宁 / 酒体 / 酒精)这副骨架做推断,香气只作佐证**——因为结构比香气更难伪装、更指

来源: synthesis.md Section 9 + Section 1.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a DIM_TITLES=(
  "地理与世界观定位（terroir-first）"
  "结构化品鉴（SAT / deductive grid）"
  "信源与分数解码"
  "配餐推理"
  "法规 / 分级 / 合规定位"
  "张力轴定位"
  "时效与近期变化"
)
declare -a DIM_QUESTIONS=(
  "这支酒来自哪(国 → 产区 → 子产区 → 地块)?属旧世界(以产地为名、terroir 至上)还是新世界(以品种 / 技术为名)?那块地的气候 / 土壤 / 法定分级如何?"
  "sight→nose→palate 各项刻度(残糖 / 酸 / 单宁 / 酒精 / 酒体 / 风味强度 / 余味);structure 骨架指向什么气候 / 产地?clean 还是 faulty(TCA / brett / VA / 还原)?"
  "这个说法 / 分数是谁说的、什么风格偏好、什么利益位置?是评论家一手长稿、trade 二手、还是众包均分?数字是单一评论家主观刻度 / 厂商自报 / 平台口径吗?"
  "菜的主导维度(脂 / 酸 / 甜 / 辣 / 蛋白)是什么?酱汁 / 烹法 / 配菜如何改变配酒?有无危险食材(芦笋 / 朝鲜蓟 / 极酸醋 / 大量辣)?是求安全和谐还是反直觉记忆点?"
  "本酒受哪套法定分级约束(AOC / AVA / PDO / Prädikat / VDP / 1855 / Saint-Émilion / Burgundy climat)?酒标合规阈值(产地 / 品种 / 年份 %)?采购受什么约束(三级分销 / DTC / 配额)?"
  "本决策 / 争议站在哪条张力轴上(干预⇄放手 / 描述⇄演绎 / 量化通约⇄风土表达 / congruent⇄complementary / 仪式⇄高效)?两端各自的正当性与代价?我方 / 对方利益与口味位置在哪?"
  "本结论会被什么侵蚀——气候(采收窗 / 适饮窗 / 演绎基线)、法规(列级重审 / 产地法改)、市场(Liv-ex 指数 / 期酒)、工具(Coravin / 数字酒单 / AI)?哪些是 high decay 须重校准?"
)
declare -a DIM_SOURCES=(
  "Oxford Companion / World Atlas of Wine(产区空间锚)、GuildSomm 产区地图、AOC cahier des charges / DOCG disciplinare、新世界看 AVA + varietal 标签。"
  "WSET SAT 网格(描述评质)或 CMS deductive grid(演绎识别)按目的选;Aroma Wheel 从中心向外缘逼近落香气词;标准物盲闻校准味觉记忆。"
  "评论家长稿(Jancis Purple Pages / Vinous / Tim Atkin 年报)而非裸聚合分;Wine-Searcher 看价不看裸分;Liv-ex 验「作为资产」的真实成交价;CellarTracker 筛 favorite tasters 后的笔记。"
  "配餐交互原则(congruent vs complementary、酸配脂 / 单宁配蛋白 / 地配地,Wine Folly / WineWiki)、危险食材清单、整桌酒序(轻→重、干→甜)。"
  "INAO(AOC / AOP)、VDP(德)、Bordeaux.com(1855)、TTB 27 CFR Part 4 / eCFR(美国酒标)、EUR-Lex(EU PDO / PGI);近期变动看德国 2021 法改 / Saint-Émilion 重审。"
  "智识谱系 5 派立场对照(Track 01 figures),把争议方落到对应奠基人 → 当前代表 → 核心分歧上。"
  "GuildSomm / Jancis / VinePair 最近期内容、Liv-ex News & Insights、Saint-Émilion / 德国法改 / EU 2021/2117、ProWein 趋势(no-low / 自然酒)。"
)
declare -a DIM_OUTPUT_FORMATS=(
  "1 句「本酒属 {旧 / 新世界},地理锚 = {产区 → 地块},风格 / 品种线索 = {…},是否受气候变暖改写地理基线」。"
  "1-2 句「结构 = {酸 / 单宁 / 酒体 / 酒精刻度},初判 = {旧 / 新世界 + 气候 + 品种},终判 = {国 / 产区 / 品种 / 酒龄 / 等级 + 可辩护理由链}」。"
  "1 句「信源 bucket = {一手 / 二手 / 众包},分数口径 = {单一评论家主观 / 平台自报 / 大众污染},可信度 = {高 / 中 / 低 + 须挂什么 caveat}」。"
  "1 句「主导维度 = {…},2-3 个安全候选 + 1 个反直觉选项,对客翻译成一句体验语言」。"
  "1 句「本酒受 {哪套分级} 约束,标签合规点 = {产地 / 品种 / 年份 % 阈值},采购渠道约束 = {三级制 / DTC / 配额}」。"
  "1 句「本问题属 {哪条轴},我方立场 = {…},对立面 = {…},别把任一端道德化成教条」。"
  "1 句「本结论衰减点 = {气候 / 法规 / 市场 / 工具中哪几条},decay = {high / medium / low},是否需重校准 + 重校准看哪个源」。"
)
declare -a DIM_FINDINGS=()

if [[ $JSON -eq 0 ]]; then
  ms_section "${INDUSTRY} · Agentic Protocol"
  ms_info "拿到的问题是什么? (输入完后，敲一个空行结束)"
  echo
fi

PROBLEM="$(ms_read_multiline)"
ms_buffer_append "# ${INDUSTRY} — Agentic Protocol Report"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## 问题"
ms_buffer_append ""
ms_buffer_append "$PROBLEM"
ms_buffer_append ""

for i in "${!DIM_TITLES[@]}"; do
  if [[ $JSON -eq 0 ]]; then
    ms_section "${DIM_TITLES[$i]}"
    echo "看什么:    ${DIM_QUESTIONS[$i]}"
    echo "在哪看:    ${DIM_SOURCES[$i]}"
    echo "输出格式:  ${DIM_OUTPUT_FORMATS[$i]}"
    echo
    ms_prompt "你的发现 / 推断 (空行结束):"
    echo
  fi
  finding="$(ms_read_multiline)"
  DIM_FINDINGS+=("$finding")

  ms_buffer_append "## ${DIM_TITLES[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**看什么**: ${DIM_QUESTIONS[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**在哪看**: ${DIM_SOURCES[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**发现**:"
  ms_buffer_append ""
  ms_buffer_append "$finding"
  ms_buffer_append ""
done

if [[ $JSON -eq 1 ]]; then
  args=("problem" "$PROBLEM")
  for i in "${!DIM_TITLES[@]}"; do
    args+=("dim_${i}_title" "${DIM_TITLES[$i]}")
    args+=("dim_${i}_finding" "${DIM_FINDINGS[$i]}")
  done
  ms_emit_json "${args[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "agentic-protocol"
fi
